```python
def derivative(f, a, b):
    return (f(b) - f(a)) / (b - a)

def main():
    try:
        a = float(input("Enter the first value (a): "))
        b = float(input("Enter the second value (b): "))
        f = input("Enter the function: ")
        if f.find("x") == -1:
            print("Invalid function. Please enter a function in terms of x.")
            return
        if a == b:
            print("The average rate of change cannot be calculated when a = b.")
            return
        else:
            result = derivative(lambda x: eval(f), a, b)
            print(f"The average rate of change is {result}.")
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()
```

