int main(int argc, char *argv[]) {
    int width = 640;
    int height = 480;

    // Initialize SDL
    if (SDL_Init(SDL_INIT_EVERYTHING)!= 0) {
        printf("Error initializing SDL: %s\n", SDL_GetError());
        return 1;
    }

    // Create the window with the specified dimensions
    SDL_Window *window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, width, height, SDL_WINDOW_SHOWN);
    if (window == NULL) {
        printf("Error creating window: %s\n", SDL_GetError());
        return 1;
    }

    // Create the renderer to draw on the window
    SDL_Renderer *renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED | SDL_RENDERER_PRESENTVSYNC);
    if (renderer == NULL) {
        printf("Error creating renderer: %s\n", SDL_GetError());
        return 1;
    }

    // Set the color palette for the renderer
    SDL_SetRenderDrawColor(renderer, 0xFF, 0xFF, 0xFF, 0xFF);

    // Initialize the game state
    game_init();

    // The main game loop
    bool running = true;
    while (running) {
        // Handle events
        handle_events(renderer);

        // Update the game state
        game_update();

        // Draw the game
        game_draw(renderer);

        // Update the screen
        SDL_RenderPresent(renderer);
    }

    // Clean up
    SDL_DestroyWindow(window);
    SDL_DestroyRenderer(renderer);
    SDL_Quit();

    return 0;
}
```

This file initializes the SDL library, creates the game window, and sets up the event handling functions. It also initializes the game state and calls the appropriate functions for updating and drawing the game.

